#include <cmath>
double newton_sqrt(double x) {
    if (x < 0) return -1;
    double guess = x / 2.0;
    while (std::abs(guess * guess - x) > 1e-10)
        guess = (guess + x / guess) / 2.0;
    return std::round(guess * 1e6) / 1e6;
}

